		// (current incorrect behavior in src/api/worker/search/MailIndexer.ts:733)
		mockEntityClient.loadMultiple.mockResolvedValue([mailDetailsBlob])

		// This simulates the buggy behavior - NOT passing session keys
		await mockEntityClient.loadMultiple("MailDetailsBlobTypeRef", "details-list-id", [
			"details-blob-id",
		])

		// Verify that NO session keys were passed (the bug)
		expect(mockEntityClient.loadMultiple).toHaveBeenCalledWith(
			"MailDetailsBlobTypeRef",
			"details-list-id",
			["details-blob-id"]
			// Missing: providedOwnerEncSessionKeys parameter
		)

		// The 4th parameter is undefined, which means the entity cannot resolve its session key
		const callArgs = mockEntityClient.loadMultiple.mock.calls[0]
		expect(callArgs.length).toBe(3) // Only 3 params, should be 4
		expect(callArgs[3]).toBeUndefined()
	})

